for k = 6:N-6
  Beta11(k) = -1/(1024*pi^10*c^11)*(lambda(k).^21*(n_eff(k+6)-11*n_eff(k+5)+55*n_eff(k+4)-165*n_eff(k+3)+330*n_eff(k+2)-462*n_eff(k+1)+462*n_eff(k)-330*n_eff(k-1)+165*n_eff(k-2)-55*n_eff(k-3)+11*n_eff(k-4)-n_eff(k-5))/del_lambda^11 +...
                                    99*lambda(k).^20*(n_eff(k+6)-10*n_eff(k+5)+45*n_eff(k+4)-120*n_eff(k+3)+210*n_eff(k+2)-252*n_eff(k+1)+210*n_eff(k)-120*n_eff(k-1)+45*n_eff(k-2)-10*n_eff(k-3)+n_eff(k-4))/del_lambda^10 +...
                                    3960*lambda(k).^19*(n_eff(k+6)-9*n_eff(k+5)+36*n_eff(k+4)-84*n_eff(k+3)+126*n_eff(k+2)-126*n_eff(k+1)+84*n_eff(k)-36*n_eff(k-1)+9*n_eff(k-2)-n_eff(k-3))/del_lambda^9 +...
                                    83160*lambda(k).^18*(n_eff(k+6)-8*n_eff(k+5)+28*n_eff(k+4)-56*n_eff(k+3)+70*n_eff(k+2)-56*n_eff(k+1)+28*n_eff(k)-8*n_eff(k-1)+n_eff(k-2))/del_lambda^8 +...
                                    997920*lambda(k).^17*(n_eff(k+6)-7*n_eff(k+5)+21*n_eff(k+4)-35*n_eff(k+3)+35*n_eff(k+2)-21*n_eff(k+1)+7*n_eff(k)-n_eff(k-1))/del_lambda^7 +...
                                    6985440*lambda(k).^16*(n_eff(k+6)-6*n_eff(k+5)+15*n_eff(k+4)-20*n_eff(k+3)+15*n_eff(k+2)-6*n_eff(k+1)+n_eff(k))/del_lambda^6 +...
                                    27941760*lambda(k).^15*(n_eff(k+6)-5*n_eff(k+5)+10*n_eff(k+4)-10*n_eff(k+3)+5*n_eff(k+2)-n_eff(k+1))/del_lambda^5 +...
                                    59875200*lambda(k).^14*(n_eff(k+6)-4*n_eff(k+5)+6*n_eff(k+4)-4*n_eff(k+3)+n_eff(k+2))/del_lambda^4 +...
                                    59875200*lambda(k).^13*(n_eff(k+6)-3*n_eff(k+5)+3*n_eff(k+4)-n_eff(k+3))/del_lambda^3 +...
                                    19958400*lambda(k).^12*(n_eff(k+6)-2*n_eff(k+5)+n_eff(k+4))/del_lambda^2);	% [Unit:ps^11/km]
